1	import { useEffect, useMemo, useRef, useState } from "react";
2	import { X } from "lucide-react";
3	import type { PanelImperativeHandle } from "react-resizable-panels";
4	import { Group, Panel, Separator } from "react-resizable-panels";
5	import { TopBar } from "./components/TopBar";
6	import { Tree } from "./components/Tree";
7	import { Viewer } from "./components/Viewer";
8	import { Query } from "./components/Query";
9	import { Palette } from "./components/Palette";
10	import { McpSettings } from "./components/McpSettings";
11	import { fetchFile, fetchProperties, fetchTree } from "./api";
12	import type { TreeNode } from "./api";
13	import { flattenTree } from "./lib/markdown";
14	
15	const ASK_ENABLED = false;
16	
17	export default function App() {
18	  const [properties, setProperties] = useState<string[]>([]);
19	  const [lie, setLie] = useState<string>("");
20	  const [tree, setTree] = useState<TreeNode | null>(null);
21	  const [path, setPath] = useState<string | null>(null);
22	  const [content, setContent] = useState<string>("");
23	  const [loading, setLoading] = useState(false);
24	  const [error, setError] = useState<string | null>(null);
25	  const [paletteOpen, setPaletteOpen] = useState(false);
26	  const [mcpSettingsOpen, setMcpSettingsOpen] = useState(false);
27	  const [askCollapsed, setAskCollapsed] = useState(false);
28	  const [treeCollapsed, setTreeCollapsed] = useState(false);
29	  const [isMobile, setIsMobile] = useState(false);
30	  const [mobileTreeOpen, setMobileTreeOpen] = useState(false);
31	  const [mobileAskOpen, setMobileAskOpen] = useState(false);
32	  const askPanelRef = useRef<PanelImperativeHandle | null>(null);
33	  const treePanelRef = useRef<PanelImperativeHandle | null>(null);
34	
35	  useEffect(() => {
36	    const mq = window.matchMedia("(max-width: 768px)");
37	    const update = () => setIsMobile(mq.matches);
38	    update();
39	    mq.addEventListener("change", update);
40	    return () => mq.removeEventListener("change", update);
41	  }, []);
42	
43	  useEffect(() => {
44	    fetchProperties()
45	      .then((ps) => {
46	        setProperties(ps);
47	        if (ps.length > 0) setLie(ps[0]);
48	      })
49	      .catch((e) => setError(String(e)));
50	  }, []);
51	
52	  useEffect(() => {
53	    if (!lie) return;
54	    setTree(null);
55	    setPath(null);
56	    setContent("");
57	    fetchTree(lie)
58	      .then((t) => {
59	        setTree(t);
60	        setPath(`${lie}/index.md`);
61	      })
62	      .catch((e) => setError(String(e)));
63	  }, [lie]);
64	
65	  useEffect(() => {
66	    if (!path) return;
67	    setLoading(true);
68	    setError(null);
69	    fetchFile(path)
70	      .then((c) => setContent(c))
71	      .catch((e) => {
72	        setError(String(e));
73	        setContent("");
74	      })
75	      .finally(() => setLoading(false));
76	  }, [path]);
77	
78	  const flatFiles = useMemo(() => (tree ? flattenTree(tree) : []), [tree]);
79	
80	  function toggleAsk() {
81	    if (isMobile) {
82	      setMobileAskOpen((v) => !v);
83	      return;
84	    }
85	    const panel = askPanelRef.current;
86	    if (!panel) return;
87	    if (panel.isCollapsed()) panel.expand();
88	    else panel.collapse();
89	  }
90	
91	  function toggleTree() {
92	    if (isMobile) {
93	      setMobileTreeOpen((v) => !v);
94	      return;
95	    }
96	    const panel = treePanelRef.current;
97	    if (!panel) return;
98	    if (panel.isCollapsed()) panel.expand();
99	    else panel.collapse();
100	  }
101	
102	  function selectPath(p: string) {
103	    setPath(p);
104	    if (isMobile) {
105	      setMobileTreeOpen(false);
106	      setMobileAskOpen(false);
107	    }
108	  }
109	
110	  const treeButtonActive = isMobile ? mobileTreeOpen : !treeCollapsed;
111	  const askButtonActive = isMobile ? mobileAskOpen : !askCollapsed;
112	
113	  const treeSidebar = (
114	    <aside className="flex h-full flex-col border-r border-[var(--color-border)] bg-[var(--color-bg)]/40">
115	      <div className="flex flex-col gap-2 border-b border-[var(--color-border)] px-3 py-2">
116	        <div className="flex items-center justify-between">
117	          <span className="font-mono text-[10.5px] uppercase tracking-[0.2em] text-[var(--color-fg-dim)]">
118	            Property
119	          </span>
120	          {tree && (
121	            <span className="font-mono text-[10.5px] text-[var(--color-fg-dim)]">
122	              {flatFiles.length} files
123	            </span>
124	          )}
125	        </div>
126	        <div className="relative">
127	          <select
128	            value={lie}
129	            onChange={(e) => setLie(e.target.value)}
130	            disabled={properties.length === 0}
131	            className="h-7 w-full cursor-pointer appearance-none rounded-md border border-[var(--color-border-2)] bg-[var(--color-surface)] px-2.5 pr-7 font-mono text-[12px] font-medium text-[var(--color-fg)] outline-none transition-colors hover:border-[var(--color-accent-dim)] focus:border-[var(--color-accent)]"
132	          >
133	            {properties.map((p) => (
134	              <option key={p} value={p}>
135	                {p}
136	              </option>
137	            ))}
138	          </select>
139	          <span className="pointer-events-none absolute right-2 top-1/2 -translate-y-1/2 text-[var(--color-fg-muted)]">
140	            <svg width="8" height="6" viewBox="0 0 8 6" fill="none">
141	              <path
142	                d="M1 1.5L4 4.5L7 1.5"
143	                stroke="currentColor"
144	                strokeWidth="1.4"
145	                strokeLinecap="round"
146	              />
147	            </svg>
148	          </span>
149	        </div>
150	      </div>
151	      <div className="flex-1 overflow-auto px-1.5 py-2">
152	        {tree ? (
153	          <Tree node={tree} selectedPath={path} onSelect={selectPath} isRoot />
154	        ) : (
155	          <TreeSkeleton />
156	        )}
157	      </div>
158	    </aside>
159	  );
160	
161	  return (
162	    <div className="flex h-screen flex-col overflow-hidden">
163	      <TopBar
164	        onOpenPalette={() => setPaletteOpen(true)}
165	        onOpenMcpSettings={() => setMcpSettingsOpen(true)}
166	        askEnabled={ASK_ENABLED}
167	        askActive={askButtonActive}
168	        onToggleAsk={toggleAsk}
169	        treeActive={treeButtonActive}
170	        onToggleTree={toggleTree}
171	      />
172	
173	      <div className="min-h-0 flex-1">
174	        {isMobile ? (
175	          <main className="flex h-full min-w-0 flex-col">
176	            <div className="min-h-0 flex-1">
177	              <Viewer
178	                path={path}
179	                content={content}
180	                loading={loading}
181	                error={error}
182	                onNavigate={selectPath}
183	              />
184	            </div>
185	          </main>
186	        ) : (
187	          <Group orientation="horizontal" className="h-full">
188	            <Panel
189	              panelRef={treePanelRef}
190	              defaultSize="20%"
191	              minSize="14%"
192	              maxSize="32%"
193	              collapsible
194	              collapsedSize="0%"
195	              onResize={(size) => setTreeCollapsed(size.asPercentage < 1)}
196	              className="tree-panel overflow-hidden"
197	            >
198	              {!treeCollapsed && treeSidebar}
199	            </Panel>
200	
201	            <Separator />
202	
203	            <Panel
204	              defaultSize={ASK_ENABLED ? "56%" : "80%"}
205	              minSize="32%"
206	              className="overflow-hidden"
207	            >
208	              <main className="flex h-full min-w-0 flex-col">
209	                <div className="min-h-0 flex-1">
210	                  <Viewer
211	                    path={path}
212	                    content={content}
213	                    loading={loading}
214	                    error={error}
215	                    onNavigate={selectPath}
216	                  />
217	                </div>
218	              </main>
219	            </Panel>
220	
221	            {ASK_ENABLED && (
222	              <>
223	                <Separator />
224	                <Panel
225	                  panelRef={askPanelRef}
226	                  defaultSize="24%"
227	                  minSize="18%"
