                "hover:border-[var(--color-accent-dim)] hover:bg-[var(--color-surface)] hover:text-[var(--color-accent)]",
                "disabled:cursor-not-allowed disabled:opacity-40",
              )}
            >
              {s}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

